+
+    server_handle.abort();
+
+    tracker.metrics(
+        "integration",
+        &E2ePerformanceMetrics::new()
+            .with_custom("port", serde_json::json!(port))
+            .with_custom("chunk_count", serde_json::json!(result.chunk_count)),
+    );
+
+    tracker.complete();
+    Ok(())
+}
